form:Form.form:Scripts:
		var Lineas=null;

function EnableButtons()
{   

	if (Ctrl("intFILE").GetXValue()=="")
	{
		Ctrl("vgrFORMATO" ).SetEnabled(false);
		Ctrl("vgrCOLUMNAS").SetEnabled(false);
	} else
	{
		Ctrl("vgrFORMATO" ).SetEnabled(true);
		Ctrl("vgrCOLUMNAS").SetEnabled(true);

		switch(Ctrl("modeDelim").GetXValue())
		{
			case "FI":
				Ctrl("sep").SetEnabled(false);
				Ctrl("fix").SetEnabled(true );
				break;

			case "DE":
				Ctrl("sep").SetEnabled(true );
				Ctrl("fix").SetEnabled(false);
				break;

			default:                      
				Ctrl("sep").SetEnabled(false);
				Ctrl("fix").SetEnabled(false);
				break;
		}  


		switch(Ctrl("colLEG").GetXValue())
		{
			case "FI": 
				Ctrl("numLEG").SetEnabled(true);
			break;
			default: 
				Ctrl("numLEG").SetEnabled(false);
			break;
		}

		switch(Ctrl("colVAR").GetXValue())
		{
			case "FI": 
				Ctrl("txtVAR").SetEnabled(true);
			break;
			default: 
				Ctrl("txtVAR").SetEnabled(false);
			break;
		}

		switch(Ctrl("colVAL").GetXValue())
		{
			case "FI": 
				Ctrl("numVAL").SetEnabled(true);
				Ctrl("forVAL").SetEnabled(false);
			break;
			case "": 
			case "NO": 
				Ctrl("numVAL").SetEnabled(false);
				Ctrl("forVAL").SetEnabled(false);
			break;
			default: 
				Ctrl("numVAL").SetEnabled(false);
				Ctrl("forVAL").SetEnabled(true);
			break;
		}

		switch(Ctrl("colPER").GetXValue())
		{
			case "FI": 
				Ctrl("numPER").SetEnabled(true);
				Ctrl("forPER").SetEnabled(false);
			break;
			case "": 
			case "NO": 
				Ctrl("numPER").SetEnabled(false);
				Ctrl("forPER").SetEnabled(false);
			break;
			default: 
				Ctrl("numPER").SetEnabled(false);
				Ctrl("forPER").SetEnabled(true);
			break;
		}
	}
}


function ShowFiles()
{     
	var html=new NomadXML("table");
	var tr,td,sep,h,myline,mysubline,min,max,prev,cols;

	html.SetAttr("style","font-size:12px;font-family:arial;");
	html.SetAttr("cellspacing","0");

	h=1;	          
	if (Ctrl("modeLINE").TypedValue()) h=Ctrl("modeLINE").TypedValue();

	switch(Ctrl("modeDelim").GetXValue())
	{
		case "FI":  
			partes=new Array();
			for (t=0; t<512; t++) partes[t]=0;

			myline=Lineas[t]; prev=1;
			for (x=0; x<6; x++)
			{
				//Extraigo la Linea
				min=Ctrl("fixCOL"+(x+1).toString()+"st").TypedValue();
				max=Ctrl("fixCOL"+(x+1).toString()+"ed").TypedValue();
				if (min==null) min=prev;
				if (max!=null)
				{             
					for (t=min; t<min+max; t++) partes[t]=(x+1);
					prev=min+max;
				} 
			}   

			//Regla
			tr=html.AddTailElement("tr");
			td=tr.AddTailElement("td");
			td.SetAttr("style","border-bottom:1px solid #888;border-right:1px solid #888;background-color:#EEE;");
			td.SetAttr(""," ");

			//Genero la Regla			
			cols=0; min=1; max=0; prev=0; myline="....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|";
			while (myline.length>0)
			{
				prev=partes[min]; max=0;
				while (partes[min+max]==prev && max<110) max++;

				cols++;
				td=tr.AddTailElement("td"); 
				td.SetAttr("style","border-bottom:1px solid #888;border-right:1px solid #888;background-color:#EEE;");
				td.AddTailElement("tt").SetAttr("",myline.substr(0, max));

				myline=myline.substr(max); min+=max;
			}         

			//Lineas 
			for (t=0; t<Lineas.length; t++)
			{   
				tr=html.AddTailElement("tr");
				td=tr.AddTailElement("td");               
				td.SetAttr("style","border-right:1px solid #888;background-color:#EEE;");
				td.AddTailElement("tt").SetAttr("",t+1);

				subcols=0; min=1; max=0; prev=0; myline=Replace(Lineas[t]," "," ");
				while (myline.length>0)
				{
					prev=partes[min]; max=0;
					while (partes[min+max]==prev && max<110) max++;

					subcols++;
					td=tr.AddTailElement("td"); 
					if (h==t+2) td.SetAttr("style","border-right:1px solid #888;border-bottom:1px solid #00F;"+(prev==0?"background-color:#BBB;":""));
					       else td.SetAttr("style","border-right:1px solid #888;"+(prev==0?"background-color:#BBB;":""));
					td.AddTailElement("tt").SetAttr("",myline.substr(0, max));

					myline=myline.substr(max); min+=max;
				}   

				if (subcols<cols)      
				{
					td=tr.AddTailElement("td"); 
					td.SetAttr("colspan", cols-subcols);
					if (h==t+2) td.SetAttr("style","border-right:1px solid #888;border-bottom:1px solid #00F;background-color:#BBB;");
					       else td.SetAttr("style","border-right:1px solid #888;background-color:#BBB;");
					td.SetAttr(""," ");
				}
			}

			break;

		case "DE":    
			sep="";      
			if (Ctrl("sepTAB").GetXValue()=="1") sep+="\t";
			if (Ctrl("sepPYC").GetXValue()=="1") sep+=";";
			if (Ctrl("sepCOM").GetXValue()=="1") sep+=",";
			if (Ctrl("sepSPC").GetXValue()=="1") sep+=" ";
			if (Ctrl("sepOTR").GetXValue()=="1") sep+=Ctrl("txtOTR").GetXValue();   

			//Regla
			tr=html.AddTailElement("tr");
			td=tr.AddTailElement("td");
			td.SetAttr("style","border-bottom:1px solid #888;border-right:1px solid #888;background-color:#EEE;");
			td.SetAttr(""," ");

			for (t=1; t<=6; t++)
			{
				td=tr.AddTailElement("td"); 
				td.SetAttr("style","border-bottom:1px solid #888;border-right:1px solid #888;background-color:#EEE;");
				td.AddTailElement("tt").SetAttr("","Columna "+t);
			}
			td=tr.AddTailElement("td"); 
			td.SetAttr("style","border-bottom:1px solid #888;background-color:#EEE;");
			td.AddTailElement("tt").SetAttr("","Otras");

			//Cabezera
			for (t=0; t<h-1; t++)
			{   
				tr=html.AddTailElement("tr");

				td=tr.AddTailElement("td");               
				td.SetAttr("style","border-right:1px solid #888;background-color:#EEE;");
				td.AddTailElement("tt").SetAttr("",t+1);

				td=tr.AddTailElement("td");
				td.SetAttr("colspan",7);
				if (h==t+2) td.SetAttr("style","border-bottom:1px solid #00F;");
				td.AddTailElement("tt").SetAttr("",Lineas[t]);
			}

			//Lineas
			for (t=h-1; t<Lineas.length; t++)
			{   
				tr=html.AddTailElement("tr");

				td=tr.AddTailElement("td");               
				td.SetAttr("style","border-right:1px solid #888;background-color:#EEE;");
				td.AddTailElement("tt").SetAttr("",t+1);


				myline=Lineas[t];
				for (x=0; x<6; x++)
				{
					td=tr.AddTailElement("td");
					td.SetAttr("style","border-right:1px solid #888;");   

					if (sep!="")
					{ 
						do {                           
							min=-1;
							for (y=0; y<sep.length; y++)
								if (myline.indexOf(sep.substr(y,1))<min || min==-1)
									min=myline.indexOf(sep.substr(y,1));

							if (min<0) 
							{
								mysubline=myline;
								myline="";
								td.SetAttr("",mysubline);
							} else
							{
								mysubline=myline.substr(0,min);
								myline=myline.substr(min+1);
								td.SetAttr("",mysubline);
							}           


						} while (myline!="" && mysubline=="" && Ctrl("sepIGN").GetXValue()=="1");
					}

					//Agrego el Espacio
					if (td.GetAttr("")=="") 
						td.SetAttr(""," ");
				}

				//Agrego la Columa Otros
				td=tr.AddTailElement("td");
				td.AddTailElement("tt").SetAttr("",myline);
			}
			break;

		default:                      
			//Regla
			tr=html.AddTailElement("tr");
			td=tr.AddTailElement("td");
			td.SetAttr("style","border-bottom:1px solid #888;border-right:1px solid #888;background-color:#EEE;");
			td.SetAttr(""," ");
			td=tr.AddTailElement("td"); 
			td.SetAttr("style","border-bottom:1px solid #888;background-color:#EEE;");
			td.AddTailElement("tt").SetAttr("","....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|....|");

      //Lineas
			for (t=0; t<Lineas.length; t++)
			{   
				tr=html.AddTailElement("tr");

				td=tr.AddTailElement("td");               
				td.SetAttr("style","border-right:1px solid #888;background-color:#EEE;");

				td.AddTailElement("tt").SetAttr("",t+1);
				td=tr.AddTailElement("td");
				if (Ctrl("modeLINE").TypedValue()==t+2)  td.SetAttr("style","border-bottom:1px solid #00F;");
				td.AddTailElement("tt").SetAttr("",Lineas[t]);

			}
			break;
	}

	Ctrl("PREVIEW").SetInner(html.ToString());
}    

function AnalizeType(value)
{   
	var aux;
	if (value?false:true) return "#";

	//Prueba Numero Entero
	aux=value.toString();
	if (aux=="+" || aux=="-") aux=aux.substr(1);
	while ((aux.substr(0,1)>='0') && (aux.substr(0,1)<='9') && (aux.length>=0))
		aux=aux.substr(1);
	if (aux=="") return "E";

	//Prueba Numero Flotante
	aux=value.toString();
	if (aux=="+" || aux=="-") aux=aux.substr(1);
	while ((aux.substr(0,1)>='0') && (aux.substr(0,1)<='9') && (aux.length>=0))
		aux=aux.substr(1);
	if (aux!="")
	{
		if (aux.substr(0,1)=="." || aux.substr(0,1)==",") aux=aux.substr(1);
		while ((aux.substr(0,1)>='0') && (aux.substr(0,1)<='9') && (aux.length>=0))
			aux=aux.substr(1);     

		if (aux=="") return "N";
	}    

	//Prueba Numero de FECHA
	aux=value.toString();
	while ((aux.substr(0,1)>='0') && (aux.substr(0,1)<='9') && (aux.length>=0))
		aux=aux.substr(1);
	if (aux!="")
	{
		if (aux.substr(0,1)=="/" || aux.substr(0,1)=="-") aux=aux.substr(1);
		while ((aux.substr(0,1)>='0') && (aux.substr(0,1)<='9') && (aux.length>=0))
			aux=aux.substr(1);     

		if (aux=="") return "F";
	}

	//Verifico si es Variable    
	aux=value.toString();	    
	if (aux.substr(2,1)!="_") return "S";
	if (aux.substr(0,1).toUpperCase()<"A" || aux.substr(0,1).toUpperCase()>"Z") return "S";
	if (aux.substr(1,1).toUpperCase()<"A" || aux.substr(1,1).toUpperCase()>"Z") return "S";

	//Otro Caso	
	return "V";
}

function FileReady()
{   
	var x,y;             
	var IDs=GetProxy().SQLService().GetXML(Ctrl("main").getResource("ROWSIDs"),"");

	//Lineas	
	Lineas=new Array();
	for (var cur=IDs.FirstChild(); cur!=null; cur=cur.Next())
		Lineas.push(cur.GetAttr("line"));         

	//Analizar el ARCHIVO (DELIMITADOR)
	delim=new Array();
	delchar=";|\t|,|F".split('|');

	//Calculo de Cantidad
	for (d=0; d<delchar.length; d++)
	{    
		delim[delchar[d]]=new Array();
		for (t=0; t<Lineas.length; t++)
		{      
			if (delchar[d]=="F") delim[delchar[d]][t]=Lineas[t].length;
			                else delim[delchar[d]][t]=Lineas[t].split(delchar[d]).length;
		}
	}             

	//Analiso Delimitadores
	for (d=0; d<delchar.length; d++)
	{ 
		sepfound="";
		count=delim[delchar[d]][1];

		if (count>=2) 
		{
			sepfound=delchar[d];
			for (t=2; t<Lineas.length; t++)
				if (count!=delim[delchar[d]][1])
				{
					sepfound="";
					break;
				}
		}  
		if (sepfound!="")
			break;
	}      

	h=0;
	if (sepfound!="")      
		h=delim[sepfound][1]==delim[sepfound][0]?1:2;

	if (sepfound=="F")
	{
		Ctrl("modeDelim").SetXValue("FI");
	} else
	if (sepfound!="")
	{      
		Ctrl("modeDelim").SetXValue("DE");
		Ctrl("sepTAB").SetXValue(sepfound=="\t"?"1":"0");
		Ctrl("sepPYC").SetXValue(sepfound==";"?"1":"0");
		Ctrl("sepCOM").SetXValue(sepfound==","?"1":"0");
		Ctrl("sepSPC").SetXValue("0");
		Ctrl("sepOTR").SetXValue("0");
		Ctrl("sepIGN").SetXValue("0");

		//Columnas
		count=delim[sepfound][1];

		//Analizando las Celdas
		str="";
		Celds=new Array();
	 	for (y=0; y<Lineas.length; y++)
	 	{
	 		Celds[y]=new Array();
			for (x=0; x<count; x++)
			{
		 		Celds[y][x]=AnalizeType(Lineas[y].split(sepfound)[x]);
		 		str+=AnalizeType(Lineas[y].split(sepfound)[x]);
		 	} 
	 		str+="\n";
		} 

	 	for (y=2; y<Lineas.length; y++)
	 	{
			for (x=0; x<count; x++)
			{       
				switch(Celds[1][x])
				{
					case "#": Celds[1][x]=Celds[y][x]; break;
					case "E":    
						if (Celds[y][x]=="E")	
							Celds[1][x]="E"; 
						else
						if (Celds[y][x]=="N")	
							Celds[1][x]="N"; 
						else
							Celds[1][x]="S";  
					break;
					case "N": 
						if (Celds[y][x]=="E")	
							Celds[1][x]="N"; 
						else
						if (Celds[y][x]=="N")	
							Celds[1][x]="N"; 
						else
							Celds[1][x]="S";  
					break;
					case "S": 
						if (Celds[y][x]=="E")	
							Celds[1][x]="N"; 
						else
						if (Celds[y][x]=="N")	
							Celds[1][x]="N"; 
						else
							Celds[1][x]="S";  
					break;              
					default:
						if (Celds[y][x]!=Celds[1][x]) Celds[1][x]="S"; 
						break;
				}
		 	} 
		}

		//Limpio los Combos      
		Ctrl("colLEG").SetXValue("NO");
		Ctrl("lblLEG").SetXValue("LEG");
		Ctrl("colVAR").SetXValue("NO");
		Ctrl("colVAL").SetXValue("NO");
		Ctrl("forVAL").SetXValue("");
		Ctrl("colPER").SetXValue("NO");

		//Analizar las Columnas
		for (x=0; x<count; x++)
		{
			if (Celds[1][x]=="E" && Ctrl("colLEG").GetXValue()=="NO") 
			{
				Ctrl("colLEG").SetXValue("C"+(x+1));
				//Ctrl("lblLEG").SetXValue("LEG");
			}
			if (Celds[1][x]=="N" && Ctrl("colVAL").GetXValue()=="NO") Ctrl("colVAL").SetXValue("C"+(x+1));
			if (Celds[1][x]=="V" && Ctrl("colVAR").GetXValue()=="NO") 
			{
				Ctrl("colVAR").SetXValue("C"+(x+1));
				Ctrl("forVAL").SetXValue("S");

				for (y=1; y<Lineas.length; y++)
				{   
					if (parseInt(Lineas[y],10)>=10000000)
						Ctrl("lblLEG").SetXValue("DNI");
				}

			}
			if (Celds[1][x]=="F" && Ctrl("colPER").GetXValue()=="NO") 
			{
				Ctrl("forPER").SetXValue("MMYYYY");
				Ctrl("colPER").SetXValue("C"+(x+1));

				for (y=1; y<Lineas.length; y++)
				{   
					mylin=Lineas[y].split(sepfound)[x];

					if(mylin.indexOf("-")>=0)
					{
						if ((parseInt(mylin.split("-")[0],10)>12) || (parseInt(mylin.split("-")[0],10)<1))
							Ctrl("forPER").SetXValue("YYYYMM");
					} else
					if(mylin.indexOf("/")>=0)
					{
						if ((parseInt(mylin.split("/")[0],10)>12) || (parseInt(mylin.split("/")[0],10)<1))
							Ctrl("forPER").SetXValue("YYYYMM");
					}

				}
			}
		}

		//Analizo la Cabezera
		if (str.split("\n")[0]!=str.split("\n")[1])
			h=2;

	} else
	{
		Ctrl("modeDelim").SetXValue("");
	}

	//Linea Inicial
	Ctrl("modeLINE").SetXValue(h!=0?h.toString():"");

 	//Actualizo el HTML
	ShowFiles();

	//Botones
	EnableButtons();
}           

function RefreshView()
{
 	//Actualizo el HTML
	ShowFiles();

	//Botones
	EnableButtons();
}
